INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Organisation administrative et comptable selon SYSCOHADA révisé', 'Formation sur l’organisation administrative et comptable conforme au SYSCOHADA révisé.', 5, 250000.00, 'entreprise', '2026-03-10', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre les principes du SYSCOHADA révisé\n• Mettre en place une organisation administrative efficace\n• Maîtriser les règles comptables et financières applicables\n• Optimiser la gestion des documents et procédures\n• Assurer la conformité légale et réglementaire\n\n--- OBJECTIFS DÉTAILLÉS ---\nInitier les participants aux fondamentaux du SYSCOHADA révisé, leur apprendre à organiser efficacement l’administration et la comptabilité, maîtriser les règles financières et assurer la conformité réglementaire.\n\n--- PRÉREQUIS ---\nConnaissances de base en comptabilité ou gestion souhaitées.\n\n--- CONTENU ---\nModule 1 : Introduction au SYSCOHADA révisé\nModule 2 : Organisation administrative et gestion documentaire\nModule 3 : Principes comptables et obligations légales\nModule 4 : Mise en place des procédures comptables\nModule 5 : Gestion financière et contrôle interne\nModule 6 : Atelier pratique – Élaboration d’un plan administratif et comptable\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nResponsables administratifs et comptables, chefs d’entreprise, gestionnaires financiers, auditeurs et toute personne impliquée dans la gestion administrative et comptable.\n\n--- MÉTHODES ---\nCours interactifs, démonstrations, études de cas, ateliers pratiques et exercices guidés.\n\n--- SUPPORTS ---\nTextes officiels SYSCOHADA révisé, modèles de procédures, tableurs Excel, supports PDF, slides et guides pratiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
